// // (1) double_bits: Halve each bit in the input vector. For example, if g = 3'b101, then double_bits should be 6'b010101.
// (2) half_bits: Double the input vector and repeat it to fill a 3-bit output vector. For example, if g = 3'b101, then half_bits should be 3'b111.
module top_module (
	input [2:0] g,
	output [5:0] double_bits,
	output [2:0] half_bits);assign double_bits = {g[2], g[2], g[1], g[1], g[0], g[0]};
	assign half_bits = {3{g[0]}};

endmodule
